function Nav({active:a,onNav}){return(<div style={{position:"fixed",bottom:0,left:0,right:0,background:"rgba(10,14,26,0.96)",backdropFilter:"blur(24px)",borderTop:`1px solid ${T.cb}`,display:"flex",justifyContent:"space-around",padding:"4px 0 env(safe-area-inset-bottom,8px)",zIndex:50}}>{TABS.map(t=>{const act=a===t.k||(["wishlist","jar","notes","photos","countdowns"].includes(a)&&t.k==="more");return(<button key={t.k} onClick={()=>onNav(t.k)} style={{background:"none",border:"none",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:1,padding:"4px 4px",position:"relative"}}><span style={{fontSize:18,filter:act?"none":"grayscale(1) opacity(0.4)"}}>{t.i}</span><span style={{fontSize:9,fontWeight:act?700:400,background:act?`linear-gradient(90deg,${T.red},${T.blue})`:"none",WebkitBackgroundClip:act?"text":"unset",WebkitTextFillColor:act?"transparent":T.t3}}>{t.l}</span>{act&&<div style={{position:"absolute",top:-1,width:16,height:2,background:`linear-gradient(90deg,${T.red},${T.blue})`,borderRadius:2}}/>}</button>)})}</div>)}
function PH({title,sub}){return(<div style={{marginBottom:16}}><h2 style={{fontSize:24,fontWeight:700,margin:0,background:`linear-gradient(90deg,${T.rl},${T.bl})`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>{title}</h2>{sub&&<p style={{fontSize:14,color:T.t3,margin:"3px 0 0"}}>{sub}</p>}</div>)}
function Anim({children,k}){return<div key={k} style={{animation:"fadeSlide 0.3s ease"}}>{children}</div>}

